import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || 'YOUR_API_KEY' });

export const generateDashboardInsights = async (metrics: any) => {
  // In a real scenario, we would pass the actual metrics JSON to the model
  // For this demo, we simulate a prompt to get a robust operational summary.

  const prompt = `
    You are an expert Warehouse Operations Analyst. 
    Analyze the following mock daily metrics for a WMS (Warehouse Management System):
    - Pending Orders: 142 (High volume)
    - Inventory Accuracy: 99.8%
    - Returns Processing: 12 items pending
    - Late Shipments: 3 (Critical)

    Provide a concise, 3-bullet point executive summary for the warehouse manager. 
    Focus on action items.
    Return only the bullet points.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback if API fails or key is missing
    return `• Prioritize the 3 late shipments immediately to avoid SLAs penalties.\n• Allocate extra resources to the packing station to handle the high volume of pending orders (142).\n• Review the 12 pending returns to clear the staging area before end of shift.`;
  }
};

import React, { useState } from 'react';
import { ChevronDown, ChevronRight, LayoutDashboard, Settings, Truck, Package, PieChart, Activity } from 'lucide-react';
import { NavItem } from '../types';

interface SidebarProps {
  navItems: NavItem[];
  activeId: string;
  onNavigate: (id: string) => void;
}

const MenuItem: React.FC<{ item: NavItem; activeId: string; onNavigate: (id: string) => void; depth?: number }> = ({ 
  item, 
  activeId, 
  onNavigate, 
  depth = 0 
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const isActive = activeId === item.id;
  const hasChildren = item.children && item.children.length > 0;

  const handleClick = () => {
    if (hasChildren) {
      setIsOpen(!isOpen);
    } else {
      onNavigate(item.id);
    }
  };

  return (
    <div className="mb-1">
      <button
        onClick={handleClick}
        className={`w-full flex items-center justify-between px-4 py-2.5 text-sm font-medium transition-colors rounded-lg
          ${isActive 
            ? 'bg-indigo-50 text-indigo-600' 
            : 'text-slate-600 hover:bg-slate-100 hover:text-slate-900'}
          ${depth > 0 ? 'pl-8' : ''}
        `}
      >
        <div className="flex items-center gap-3">
          {item.icon && <item.icon size={18} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />}
          <span>{item.title}</span>
        </div>
        {hasChildren && (
          isOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />
        )}
      </button>

      {hasChildren && isOpen && (
        <div className="mt-1 space-y-1">
          {item.children!.map((child) => (
            <MenuItem 
              key={child.id} 
              item={child} 
              activeId={activeId} 
              onNavigate={onNavigate} 
              depth={depth + 1} 
            />
          ))}
        </div>
      )}
    </div>
  );
};

