        </div>

        {isDashboard ? (
          <Dashboard />
        ) : (
          <ModuleView 
            key={activeId} // Force re-render on switch
            title={activeTitle} 
            type={isReport ? 'report' : 'list'} 
          />
        )}
      </main>
    </div>
  );
}

export default App;

