interface SidebarProps {
  navItems: NavItem[];
  activeId: string;
  onNavigate: (id: string) => void;
}

const MenuItem: React.FC<{ item: NavItem; activeId: string; onNavigate: (id: string) => void; depth?: number }> = ({ 
  item, 
  activeId, 
  onNavigate, 
  depth = 0 
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const isActive = activeId === item.id;
  const hasChildren = item.children && item.children.length > 0;

  const handleClick = () => {
    if (hasChildren) {
      setIsOpen(!isOpen);
    } else {
      onNavigate(item.id);
    }
  };

  return (
    <div className="mb-1">
      <button
        onClick={handleClick}
        className={`w-full flex items-center justify-between px-4 py-2.5 text-sm font-medium transition-colors rounded-lg
          ${isActive 
            ? 'bg-indigo-50 text-indigo-600' 
            : 'text-slate-600 hover:bg-slate-100 hover:text-slate-900'}
          ${depth > 0 ? 'pl-8' : ''}
        `}
      >
        <div className="flex items-center gap-3">
          {item.icon && <item.icon size={18} className={isActive ? 'text-indigo-600' : 'text-slate-400'} />}
          <span>{item.title}</span>
        </div>
        {hasChildren && (
          isOpen ? <ChevronDown size={14} /> : <ChevronRight size={14} />
        )}
      </button>

      {hasChildren && isOpen && (
        <div className="mt-1 space-y-1">
          {item.children!.map((child) => (
            <MenuItem 
              key={child.id} 
              item={child} 
              activeId={activeId} 
              onNavigate={onNavigate} 
              depth={depth + 1} 
            />
          ))}
        </div>
      )}
    </div>
  );
};

