                        ${row.status === '已完成' || row.status === '正常' ? 'bg-green-100 text-green-800' : 
                          row.status === '待处理' ? 'bg-yellow-100 text-yellow-800' : 'bg-slate-100 text-slate-800'}
                    `}>
                        {row.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-slate-500">
                    2023-10-2{idx}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="text-slate-400 hover:text-indigo-600 transition-colors">
                        <MoreHorizontal size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        <div className="px-6 py-4 border-t border-slate-100 flex items-center justify-between text-sm text-slate-500">
            <span>显示 1 到 8 条，共 124 条</span>
            <div className="flex gap-2">
                <button className="px-3 py-1 border border-slate-200 rounded hover:bg-slate-50 disabled:opacity-50">上一页</button>
                <button className="px-3 py-1 border border-slate-200 rounded hover:bg-slate-50">下一页</button>
            </div>
        </div>
      </div>
    </div>
  );
};

