function App() {
  const [activeId, setActiveId] = useState('dashboard');
  const [activeTitle, setActiveTitle] = useState('首页');

  const handleNavigate = (id: string) => {
    setActiveId(id);

    // Find title recursively (helper function)
    const findTitle = (items: NavItem[]): string => {
        for (const item of items) {
            if (item.id === id) return item.title;
            if (item.children) {
                const found = findTitle(item.children);
                if (found) return found;
            }
        }
        return '';
    };

    const title = findTitle(navItems);
    if(title) setActiveTitle(title);
  };

  const isDashboard = activeId === 'dashboard';
  // Check if it's a report page to render report view type
  const isReport = activeId.startsWith('rep-');

  return (
    <div className="flex min-h-screen bg-[#f8fafc]">
      <Sidebar navItems={navItems} activeId={activeId} onNavigate={handleNavigate} />

      <main className="flex-1 ml-64 p-8 overflow-x-hidden">
        {/* Top Header Mockup (User context already in sidebar bottom, but typically breadcrumbs go here) */}
        <div className="mb-8 flex items-center text-sm text-slate-400">
           <span>应用</span>
           <span className="mx-2">/</span>
           <span className="text-slate-900 font-medium">{activeTitle}</span>
        </div>

        {isDashboard ? (
          <Dashboard />
        ) : (
          <ModuleView 
            key={activeId} // Force re-render on switch
            title={activeTitle} 
            type={isReport ? 'report' : 'list'} 
          />
        )}
      </main>
    </div>
  );
}

export default App;
